#[derive(Clone)]
#[napi]
pub struct JsTessdataManager {
    inner: Arc<kreuzberg::ocr::TessdataManager>,
}

#[napi]
impl JsTessdataManager {
    #[napi(js_name = "cacheDir")]
    pub fn cache_dir(&self) -> String {
        self.inner.cache_dir().to_string_lossy().to_string()
    }

    #[napi(js_name = "isLanguageCached")]
    pub fn is_language_cached(&self, lang: String) -> bool {
        self.inner.is_language_cached(&lang)
    }

    #[allow(clippy::missing_errors_doc)]
    #[napi(js_name = "ensureAllLanguages")]
    pub fn ensure_all_languages(&self) -> Result<i64> {
        let result = self
            .inner
            .ensure_all_languages()
            .map_err(|e| napi::Error::new(napi::Status::GenericFailure, e.to_string()))?;
        Ok(result as i64)
    }
}

