// Error variant name constants
pub const KREUZBERG_ERROR_ERROR_IO: &str = "Io";
pub const KREUZBERG_ERROR_ERROR_PARSING: &str = "Parsing";
pub const KREUZBERG_ERROR_ERROR_OCR: &str = "Ocr";
pub const KREUZBERG_ERROR_ERROR_VALIDATION: &str = "Validation";
pub const KREUZBERG_ERROR_ERROR_CACHE: &str = "Cache";
pub const KREUZBERG_ERROR_ERROR_IMAGE_PROCESSING: &str = "ImageProcessing";
pub const KREUZBERG_ERROR_ERROR_SERIALIZATION: &str = "Serialization";
pub const KREUZBERG_ERROR_ERROR_MISSING_DEPENDENCY: &str = "MissingDependency";
pub const KREUZBERG_ERROR_ERROR_PLUGIN: &str = "Plugin";
pub const KREUZBERG_ERROR_ERROR_LOCK_POISONED: &str = "LockPoisoned";
pub const KREUZBERG_ERROR_ERROR_UNSUPPORTED_FORMAT: &str = "UnsupportedFormat";
pub const KREUZBERG_ERROR_ERROR_EMBEDDING: &str = "Embedding";
pub const KREUZBERG_ERROR_ERROR_TIMEOUT: &str = "Timeout";
pub const KREUZBERG_ERROR_ERROR_CANCELLED: &str = "Cancelled";
pub const KREUZBERG_ERROR_ERROR_SECURITY: &str = "Security";
pub const KREUZBERG_ERROR_ERROR_OTHER: &str = "Other";

/// Convert a `kreuzberg::error::KreuzbergError` error to a NAPI error.
#[allow(dead_code)]
fn kreuzberg_error_to_napi_err(e: kreuzberg::error::KreuzbergError) -> napi::Error {
    let msg = e.to_string();
    #[allow(unreachable_patterns)]
    match &e {
        kreuzberg::error::KreuzbergError::Io(..) => {
            napi::Error::new(napi::Status::GenericFailure, format!("[Io] {}", msg))
        }
        kreuzberg::error::KreuzbergError::Parsing { .. } => {
            napi::Error::new(napi::Status::GenericFailure, format!("[Parsing] {}", msg))
        }
        kreuzberg::error::KreuzbergError::Ocr { .. } => {
            napi::Error::new(napi::Status::GenericFailure, format!("[Ocr] {}", msg))
        }
        kreuzberg::error::KreuzbergError::Validation { .. } => {
            napi::Error::new(napi::Status::GenericFailure, format!("[Validation] {}", msg))
        }
        kreuzberg::error::KreuzbergError::Cache { .. } => {
            napi::Error::new(napi::Status::GenericFailure, format!("[Cache] {}", msg))
        }
        kreuzberg::error::KreuzbergError::ImageProcessing { .. } => {
            napi::Error::new(napi::Status::GenericFailure, format!("[ImageProcessing] {}", msg))
        }
        kreuzberg::error::KreuzbergError::Serialization { .. } => {
            napi::Error::new(napi::Status::GenericFailure, format!("[Serialization] {}", msg))
        }
        kreuzberg::error::KreuzbergError::MissingDependency(..) => {
            napi::Error::new(napi::Status::GenericFailure, format!("[MissingDependency] {}", msg))
        }
        kreuzberg::error::KreuzbergError::Plugin { .. } => {
            napi::Error::new(napi::Status::GenericFailure, format!("[Plugin] {}", msg))
        }
        kreuzberg::error::KreuzbergError::LockPoisoned(..) => {
            napi::Error::new(napi::Status::GenericFailure, format!("[LockPoisoned] {}", msg))
        }
        kreuzberg::error::KreuzbergError::UnsupportedFormat(..) => {
            napi::Error::new(napi::Status::GenericFailure, format!("[UnsupportedFormat] {}", msg))
        }
        kreuzberg::error::KreuzbergError::Embedding { .. } => {
            napi::Error::new(napi::Status::GenericFailure, format!("[Embedding] {}", msg))
        }
        kreuzberg::error::KreuzbergError::Timeout { .. } => {
            napi::Error::new(napi::Status::GenericFailure, format!("[Timeout] {}", msg))
        }
        kreuzberg::error::KreuzbergError::Cancelled => {
            napi::Error::new(napi::Status::GenericFailure, format!("[Cancelled] {}", msg))
        }
        kreuzberg::error::KreuzbergError::Security { .. } => {
            napi::Error::new(napi::Status::GenericFailure, format!("[Security] {}", msg))
        }
        kreuzberg::error::KreuzbergError::Other(..) => {
            napi::Error::new(napi::Status::GenericFailure, format!("[Other] {}", msg))
        }
        _ => napi::Error::new(napi::Status::GenericFailure, msg),
    }
}
